  1→import { useEffect, useRef, useCallback } from "react";
  2→import { init, Terminal } from "ghostty-web";
  3→import { FitAddon } from "ghostty-web";
  4→import { invoke } from "@tauri-apps/api/core";
  5→import { useTauriEvent } from "../../hooks/use-tauri-event";
  6→
  7→let wasmReady: Promise<void> | null = null;
  8→function ensureInit(): Promise<void> {
  9→  if (!wasmReady) wasmReady = init();
 10→  return wasmReady;
 11→}
 12→
 13→interface XTerminalProps {
 14→  sessionId: string | null;
 15→  className?: string;
 16→}
 17→
 18→export function XTerminal({ sessionId, className }: XTerminalProps) {
 19→  const containerRef = useRef<HTMLDivElement>(null);
 20→  const termRef = useRef<Terminal | null>(null);
 21→  const fitAddonRef = useRef<FitAddon | null>(null);
 22→
 23→  // Handle PTY output from Rust backend
 24→  useTauriEvent<{ sessionId: string; data: number[] }>(
 25→    "pty-output",
 26→    useCallback(
 27→      (payload) => {
 28→        if (payload.sessionId === sessionId && termRef.current) {
 29→          const bytes = new Uint8Array(payload.data);
 30→          termRef.current.write(bytes);
 31→        }
 32→      },
 33→      [sessionId]
 34→    )
 35→  );
 36→
 37→  useEffect(() => {
 38→    if (!containerRef.current) return;
 39→    let disposed = false;
 40→    let term: Terminal | null = null;
 41→    let fitAddon: FitAddon | null = null;
 42→    let resizeObserver: ResizeObserver | null = null;
 43→
 44→    ensureInit().then(() => {
 45→      if (disposed || !containerRef.current) return;
 46→
 47→      term = new Terminal({
 48→        fontFamily: "'SF Mono', 'Fira Code', 'Cascadia Code', monospace",
 49→        fontSize: 13,
 50→        cursorBlink: true,
 51→        cursorStyle: "block",
 52→        theme: {
 53→          background: "#0a0a0a",
 54→          foreground: "#e4e4e7",
 55→          cursor: "#7c3aed",
 56→          cursorAccent: "#0a0a0a",
 57→          selectionBackground: "#7c3aed44",
 58→          black: "#0d0d0d",
 59→          red: "#f87171",
 60→          green: "#4ade80",
 61→          yellow: "#fbbf24",
 62→          blue: "#60a5fa",
 63→          magenta: "#a78bfa",
 64→          cyan: "#22d3ee",
 65→          white: "#e4e4e7",
 66→          brightBlack: "#555555",
 67→          brightRed: "#fca5a5",
 68→          brightGreen: "#86efac",
 69→          brightYellow: "#fde68a",
 70→          brightBlue: "#93c5fd",
 71→          brightMagenta: "#c4b5fd",
 72→          brightCyan: "#67e8f9",
 73→          brightWhite: "#ffffff",
 74→        },
 75→      });
 76→
 77→      fitAddon = new FitAddon();
 78→      term.loadAddon(fitAddon);
 79→      term.open(containerRef.current!);
 80→
 81→      requestAnimationFrame(() => {
 82→        fitAddon?.fit();
 83→      });
 84→
 85→      // Send user input to PTY
 86→      term.onData((data: string) => {
 87→        if (sessionId) {
 88→          invoke("pty_input", { sessionId, data }).catch(console.error);
 89→        }
 90→      });
 91→
 92→      // Resize PTY when terminal resizes
 93→      term.onResize(({ cols, rows }: { cols: number; rows: number }) => {
 94→        if (sessionId) {
 95→          invoke("pty_resize", { sessionId, cols, rows }).catch(console.error);
 96→        }
 97→      });
 98→
 99→      termRef.current = term;
100→      fitAddonRef.current = fitAddon;
101→
102→      resizeObserver = new ResizeObserver(() => {
103→        requestAnimationFrame(() => {
104→          fitAddon?.fit();
105→        });
106→      });
107→      resizeObserver.observe(containerRef.current!);
108→
109→      // Welcome message if no session
110→      if (!sessionId) {
111→        term.writeln("\x1b[38;2;124;58;237m");
112→        term.writeln("  ╔═══════════════════════════════════╗");
113→        term.writeln("  ║         Entire Desktop            ║");
114→        term.writeln("  ║                                   ║");
115→        term.writeln("  ║  Launch an agent to get started   ║");
116→        term.writeln("  ╚═══════════════════════════════════╝");
117→        term.writeln("\x1b[0m");
118→      }
119→    });
120→
121→    return () => {
122→      disposed = true;
123→      resizeObserver?.disconnect();
124→      term?.dispose();
125→      termRef.current = null;
126→      fitAddonRef.current = null;
127→    };
128→  }, [sessionId]);
129→
130→  return (
131→    <div
132→      ref={containerRef}
133→      className={`h-full w-full ${className ?? ""}`}
134→      style={{ padding: "4px 8px" }}
135→    />
136→  );
137→}
