  1→import { useCallback, useImperativeHandle, forwardRef } from "react";
  2→import { invoke } from "@tauri-apps/api/core";
  3→import { XTerminal } from "./XTerminal";
  4→import type { Tab } from "../../App";
  5→
  6→export interface TermSession {
  7→  id: string;
  8→  agent: string;
  9→  label: string;
 10→}
 11→
 12→export interface TerminalPanelHandle {
 13→  launchAgentWithPrompt: (agent: string, prompt: string) => Promise<void>;
 14→}
 15→
 16→interface TerminalPanelProps {
 17→  height: number;
 18→  tab: Tab;
 19→  session: TermSession | null;
 20→  onSessionChange: (session: TermSession | null) => void;
 21→  onToggle: () => void;
 22→}
 23→
 24→export const TerminalPanel = forwardRef<TerminalPanelHandle, TerminalPanelProps>(
 25→  function TerminalPanel({ height, tab, session, onSessionChange, onToggle }, ref) {
 26→
 27→    const launchAgent = useCallback(
 28→      async (agent: string) => {
 29→        if (!tab.repoPath) {
 30→          console.warn("No repo path set — cannot launch agent");
 31→          return "";
 32→        }
 33→        try {
 34→          const sessionId: string = await invoke("spawn_agent", {
 35→            repoPath: tab.repoPath,
 36→            agent,
 37→          });
 38→          const newSession: TermSession = {
 39→            id: sessionId,
 40→            agent,
 41→            label: `${agent === "claude-code" ? "Claude Code" : "Codex"} — ${tab.branch}`,
 42→          };
 43→          onSessionChange(newSession);
 44→          return sessionId;
 45→        } catch (err) {
 46→          console.error("Failed to spawn agent:", err);
 47→          return "";
 48→        }
 49→      },
 50→      [tab.repoPath, tab.branch, onSessionChange]
 51→    );
 52→
 53→    const killSession = useCallback(async () => {
 54→      if (!session) return;
 55→      try {
 56→        await invoke("kill_pty", { sessionId: session.id });
 57→      } catch (err) {
 58→        console.error("Failed to kill session:", err);
 59→      }
 60→      onSessionChange(null);
 61→    }, [session, onSessionChange]);
 62→
 63→    useImperativeHandle(ref, () => ({
 64→      async launchAgentWithPrompt(agent: string, prompt: string) {
 65→        const sessionId = await launchAgent(agent);
 66→        if (!sessionId) return;
 67→        setTimeout(async () => {
 68→          try {
 69→            await invoke("pty_input", { sessionId, data: prompt + "\n" });
 70→          } catch (err) {
 71→            console.error("Failed to send prompt to agent:", err);
 72→          }
 73→        }, 150);
 74→      },
 75→    }), [launchAgent]);
 76→
 77→    return (
 78→      <div className="flex shrink-0 flex-col bg-[#0a0a0a]" style={{ height }}>
 79→        {/* Terminal header */}
 80→        <div className="flex items-center gap-2 border-t border-border bg-bg-raised px-3 py-1.5">
 81→          {session ? (
 82→            <>
 83→              <span className="flex items-center gap-1.5 text-[11px] text-fg-muted">
 84→                <span className="h-1.5 w-1.5 animate-pulse rounded-full bg-green" />
 85→                {session.label}
 86→              </span>
 87→              <button
 88→                onClick={killSession}
 89→                className="rounded-md border border-border-subtle px-2 py-0.5 text-[11px] text-fg-subtle transition-colors hover:border-red hover:text-red"
 90→              >
 91→                Kill
 92→              </button>
 93→            </>
 94→          ) : (
 95→            <>
 96→              <button
 97→                onClick={() => launchAgent("claude-code")}
 98→                className="flex items-center gap-1.5 rounded-md border border-border-subtle px-2.5 py-1 text-[11px] text-fg-subtle transition-colors hover:border-accent hover:text-accent-fg"
 99→              >
100→                Claude Code
101→              </button>
102→              <button
103→                onClick={() => launchAgent("codex")}
104→                className="flex items-center gap-1.5 rounded-md border border-border-subtle px-2.5 py-1 text-[11px] text-fg-subtle transition-colors hover:border-green hover:text-green"
105→              >
106→                Codex
107→              </button>
108→              <span className="text-[11px] text-fg-subtle">Launch ▸</span>
109→            </>
110→          )}
111→
112→          <button
113→            onClick={onToggle}
114→            className="ml-auto px-2 py-1 text-[11px] text-fg-subtle hover:text-fg-muted"
115→          >
116→            ⌃` Toggle ▾
117→          </button>
118→        </div>
119→
120→        {/* Terminal body */}
121→        <div className="flex-1 overflow-hidden">
122→          <XTerminal sessionId={session?.id ?? null} />
123→        </div>
124→      </div>
125→    );
126→  }
127→);
