 82→/// Read a blob from the entire/checkpoints/v1 branch by path
 83→fn read_blob(repo: &git2::Repository, path: &str) -> Result<String, String> {
 84→    let branch_ref = repo
 85→        .find_branch("entire/checkpoints/v1", git2::BranchType::Local)
 86→        .map_err(|e| format!("No checkpoint branch: {}", e))?;
 87→
 88→    let commit = branch_ref
 89→        .get()
 90→        .peel_to_commit()
 91→        .map_err(|e| format!("Failed to peel: {}", e))?;
 92→
 93→    let tree = commit
 94→        .tree()
 95→        .map_err(|e| format!("Failed to get tree: {}", e))?;
 96→
 97→    let entry = tree
 98→        .get_path(std::path::Path::new(path))
 99→        .map_err(|e| format!("Path not found: {}", e))?;
100→
101→    let blob = repo
102→        .find_blob(entry.id())
103→        .map_err(|e| format!("Failed to read blob: {}", e))?;
104→
105→    std::str::from_utf8(blob.content())
106→        .map(|s| s.to_string())
107→        .map_err(|e| format!("Invalid UTF-8: {}", e))
108→}
