157→#[tauri::command]
158→fn get_checkpoint_logs(
159→    repo_path: String,
160→    checkpoint_id: String,
161→    session_ids: Vec<String>,
162→) -> Result<EntireLogResult, String> {
163→    let log_path = std::path::Path::new(&repo_path).join(".entire/logs/entire.log");
164→    if !log_path.exists() {
165→        return Ok(EntireLogResult {
166→            lines: Vec::new(),
167→            total_lines: 0,
168→            file_size_bytes: 0,
169→        });
170→    }
171→
172→    let metadata = std::fs::metadata(&log_path)
173→        .map_err(|e| format!("Failed to read log metadata: {}", e))?;
174→    let file_size_bytes = metadata.len();
175→
176→    let file = std::fs::File::open(&log_path)
177→        .map_err(|e| format!("Failed to open log file: {}", e))?;
178→
179→    let reader = BufReader::new(file);
180→    let mut matching_lines = Vec::new();
181→    let mut total_lines: u32 = 0;
182→
183→    for line in reader.lines() {
184→        let line = match line {
185→            Ok(l) => l,
186→            Err(_) => continue,
187→        };
188→        total_lines += 1;
189→
190→        // Parse each line as JSON and check for matching session_id or checkpoint_id
191→        if let Ok(value) = serde_json::from_str::<serde_json::Value>(&line) {
192→            let line_session_id = value.get("session_id").and_then(|v| v.as_str());
193→            let line_checkpoint_id = value.get("checkpoint_id").and_then(|v| v.as_str());
194→
195→            let matches = line_session_id
196→                .map(|sid| session_ids.iter().any(|s| s == sid))
197→                .unwrap_or(false)
198→                || line_checkpoint_id
199→                    .map(|cid| cid == checkpoint_id)
200→                    .unwrap_or(false);
201→
202→            if matches {
203→                matching_lines.push(line);
204→            }
205→        }
206→    }
207→
208→    Ok(EntireLogResult {
209→        total_lines: matching_lines.len() as u32,
210→        lines: matching_lines,
211→        file_size_bytes,
212→    })
213→}
