296→#[derive(serde::Serialize)]
297→struct FileDiff {
298→    path: String,
299→    status: String, // "added", "modified", "deleted"
300→    hunks: Vec<DiffHunk>,
301→}
302→
303→#[derive(serde::Serialize)]
304→struct DiffHunk {
305→    header: String,
306→    lines: Vec<DiffLine>,
307→}
308→
309→#[derive(serde::Serialize)]
310→struct DiffLine {
311→    kind: String, // "add", "delete", "context"
312→    content: String,
313→    old_lineno: Option<u32>,
314→    new_lineno: Option<u32>,
315→}
316→
317→/// Convert a git2::Diff into our FileDiff structs
318→fn collect_diff_files(diff: &git2::Diff) -> Result<Vec<FileDiff>, String> {
319→    let mut files: Vec<FileDiff> = Vec::new();
320→
321→    diff.print(git2::DiffFormat::Patch, |delta, hunk, line| {
322→        let path = delta
323→            .new_file()
324→            .path()
325→            .or_else(|| delta.old_file().path())
326→            .map(|p| p.to_string_lossy().to_string())
327→            .unwrap_or_default();
328→
329→        let status = match delta.status() {
330→            git2::Delta::Added => "added",
331→            git2::Delta::Deleted => "deleted",
332→            _ => "modified",
333→        };
334→
335→        // Ensure we have a FileDiff entry for this path
336→        if files.last().map_or(true, |f| f.path != path) {
337→            files.push(FileDiff {
338→                path: path.clone(),
339→                status: status.to_string(),
340→                hunks: Vec::new(),
341→            });
342→        }
343→
344→        let file = files.last_mut().unwrap();
345→
346→        // New hunk
347→        if let Some(h) = hunk {
348→            let header = std::str::from_utf8(h.header()).unwrap_or("").to_string();
349→            if file.hunks.last().map_or(true, |last| last.header != header) {
350→                file.hunks.push(DiffHunk {
351→                    header,
352→                    lines: Vec::new(),
353→                });
354→            }
355→        }
356→
357→        // Diff line
358→        if let Some(current_hunk) = file.hunks.last_mut() {
359→            let kind = match line.origin() {
360→                '+' => "add",
361→                '-' => "delete",
362→                ' ' => "context",
363→                _ => return true,
364→            };
365→            let content = std::str::from_utf8(line.content()).unwrap_or("").to_string();
366→            current_hunk.lines.push(DiffLine {
367→                kind: kind.to_string(),
368→                content,
369→                old_lineno: line.old_lineno(),
370→                new_lineno: line.new_lineno(),
371→            });
372→        }
373→
374→        true
375→    })
376→    .map_err(|e| format!("Failed to print diff: {}", e))?;
377→
378→    Ok(files)
379→}
