381→#[tauri::command]
382→fn get_checkpoint_diff(
383→    repo_path: String,
384→    commit_sha: String,
385→) -> Result<Vec<FileDiff>, String> {
386→    if commit_sha.is_empty() {
387→        return Err("No commit SHA available for this checkpoint".to_string());
388→    }
389→
390→    let repo = git::open_repo(&repo_path)?;
391→    let oid = git2::Oid::from_str(&commit_sha)
392→        .map_err(|e| format!("Invalid commit SHA: {}", e))?;
393→    let commit = repo
394→        .find_commit(oid)
395→        .map_err(|e| format!("Commit not found: {}", e))?;
396→
397→    let tree = commit
398→        .tree()
399→        .map_err(|e| format!("Failed to get tree: {}", e))?;
400→
401→    // Diff against parent (or empty tree if no parent)
402→    let parent_tree = commit
403→        .parent(0)
404→        .ok()
405→        .and_then(|p| p.tree().ok());
406→
407→    let diff = repo
408→        .diff_tree_to_tree(parent_tree.as_ref(), Some(&tree), None)
409→        .map_err(|e| format!("Failed to compute diff: {}", e))?;
410→
411→    collect_diff_files(&diff)
412→}
413→
414→#[tauri::command]
415→fn get_branch_diff(
416→    repo_path: String,
417→    branch: String,
418→) -> Result<Vec<FileDiff>, String> {
419→    let repo = git::open_repo(&repo_path)?;
420→
421→    // Resolve the branch HEAD
422→    let branch_ref = repo
423→        .find_branch(&branch, git2::BranchType::Local)
424→        .map_err(|e| format!("Branch not found: {}", e))?;
425→    let branch_commit = branch_ref
426→        .get()
427→        .peel_to_commit()
428→        .map_err(|e| format!("Failed to resolve branch HEAD: {}", e))?;
429→
430→    // Find the default branch (try main, then master)
431→    let default_branch_name = if repo.find_branch("main", git2::BranchType::Local).is_ok() {
432→        "main"
433→    } else if repo.find_branch("master", git2::BranchType::Local).is_ok() {
434→        "master"
435→    } else {
436→        return Err("No default branch (main/master) found".to_string());
437→    };
438→
439→    // If we're diffing the default branch against itself, return empty
440→    if branch == default_branch_name {
441→        return Ok(Vec::new());
442→    }
443→
444→    let default_ref = repo
445→        .find_branch(default_branch_name, git2::BranchType::Local)
446→        .map_err(|e| format!("Default branch error: {}", e))?;
447→    let default_commit = default_ref
448→        .get()
449→        .peel_to_commit()
450→        .map_err(|e| format!("Failed to resolve default branch: {}", e))?;
451→
452→    // Find merge base
453→    let merge_base_oid = repo
454→        .merge_base(default_commit.id(), branch_commit.id())
455→        .map_err(|e| format!("Failed to find merge base: {}", e))?;
456→    let merge_base_commit = repo
457→        .find_commit(merge_base_oid)
458→        .map_err(|e| format!("Failed to find merge base commit: {}", e))?;
459→
460→    let base_tree = merge_base_commit
461→        .tree()
462→        .map_err(|e| format!("Failed to get base tree: {}", e))?;
463→    let branch_tree = branch_commit
464→        .tree()
465→        .map_err(|e| format!("Failed to get branch tree: {}", e))?;
466→
467→    let diff = repo
468→        .diff_tree_to_tree(Some(&base_tree), Some(&branch_tree), None)
469→        .map_err(|e| format!("Failed to compute branch diff: {}", e))?;
470→
471→    collect_diff_files(&diff)
472→}
