474→#[tauri::command]
475→fn watch_repo(
476→    repo_path: String,
477→    app: tauri::AppHandle,
478→    state: State<'_, Mutex<AppState>>,
479→) -> Result<(), String> {
480→    let mut app_state = state.lock().map_err(|_| "State lock error".to_string())?;
481→
482→    // Don't double-watch
483→    if app_state.watched_repos.contains(&repo_path) {
484→        return Ok(());
485→    }
486→    app_state.watched_repos.insert(repo_path.clone());
487→
488→    let app_handle = app.clone();
489→    let repo_path_for_closure = repo_path.clone();
490→    watcher::watch_repo(&repo_path, move |event| {
491→        let event_name = match event {
492→            watcher::WatchEvent::CheckpointChanged => "checkpoint-changed",
493→            watcher::WatchEvent::SessionChanged(_) => "session-changed",
494→            watcher::WatchEvent::ConfigChanged => "config-changed",
495→        };
496→        let _ = app_handle.emit(event_name, serde_json::json!({
497→            "repoPath": repo_path_for_closure,
498→        }));
499→    })?;
500→
501→    Ok(())
502→}
