  1→use portable_pty::{native_pty_system, CommandBuilder, PtySize};
  2→use serde::Serialize;
  3→use std::collections::HashMap;
  4→use std::io::{Read, Write};
  5→use std::sync::{Arc, Mutex};
  6→
  7→#[derive(Debug, Serialize, Clone)]
  8→pub struct PtySessionInfo {
  9→    pub id: String,
 10→    pub agent: String,
 11→    pub repo_path: String,
 12→}
 13→
 14→pub struct PtyManager {
 15→    sessions: Arc<Mutex<HashMap<String, PtySession>>>,
 16→}
 17→
 18→struct PtySession {
 19→    writer: Box<dyn Write + Send>,
 20→    master: Box<dyn portable_pty::MasterPty + Send>,
 21→    _child: Box<dyn portable_pty::Child + Send + Sync>,
 22→    #[allow(dead_code)]
 23→    info: PtySessionInfo,
 24→}
 25→
 26→impl PtyManager {
 27→    pub fn new() -> Self {
 28→        Self {
 29→            sessions: Arc::new(Mutex::new(HashMap::new())),
 30→        }
 31→    }
 32→
 33→    pub fn spawn(
 34→        &self,
 35→        agent: &str,
 36→        repo_path: &str,
 37→        event_emitter: impl Fn(String, Vec<u8>) + Send + 'static,
 38→    ) -> Result<String, String> {
 39→        let pty_system = native_pty_system();
 40→
 41→        let pair = pty_system
 42→            .openpty(PtySize {
 43→                rows: 24,
 44→                cols: 80,
 45→                pixel_width: 0,
 46→                pixel_height: 0,
 47→            })
 48→            .map_err(|e| format!("Failed to open PTY: {}", e))?;
 49→
 50→        let cmd = match agent {
 51→            "claude-code" => {
 52→                let mut cmd = CommandBuilder::new("claude");
 53→                cmd.cwd(repo_path);
 54→                cmd
 55→            }
 56→            "codex" => {
 57→                let mut cmd = CommandBuilder::new("codex");
 58→                cmd.cwd(repo_path);
 59→                cmd
 60→            }
 61→            _ => return Err(format!("Unknown agent: {}", agent)),
 62→        };
 63→
 64→        let child = pair
 65→            .slave
 66→            .spawn_command(cmd)
 67→            .map_err(|e| format!("Failed to spawn: {}", e))?;
 68→
 69→        let session_id = uuid_v4();
 70→        let writer = pair
 71→            .master
 72→            .take_writer()
 73→            .map_err(|e| format!("Failed to get writer: {}", e))?;
 74→
 75→        let info = PtySessionInfo {
 76→            id: session_id.clone(),
 77→            agent: agent.to_string(),
 78→            repo_path: repo_path.to_string(),
 79→        };
 80→
 81→        // Spawn reader thread to stream output
 82→        let mut reader = pair
 83→            .master
 84→            .try_clone_reader()
 85→            .map_err(|e| format!("Failed to clone reader: {}", e))?;
 86→
 87→        let sid = session_id.clone();
 88→        std::thread::spawn(move || {
 89→            let mut buf = [0u8; 4096];
 90→            loop {
 91→                match reader.read(&mut buf) {
 92→                    Ok(0) => break,
 93→                    Ok(n) => {
 94→                        event_emitter(sid.clone(), buf[..n].to_vec());
 95→                    }
 96→                    Err(_) => break,
 97→                }
 98→            }
 99→        });
100→
101→        let session = PtySession {
102→            writer,
103→            master: pair.master,
104→            _child: child,
105→            info,
106→        };
107→
108→        self.sessions
109→            .lock()
110→            .map_err(|_| "Lock error".to_string())?
111→            .insert(session_id.clone(), session);
112→
113→        Ok(session_id)
114→    }
115→
116→    pub fn write(&self, session_id: &str, data: &[u8]) -> Result<(), String> {
117→        let mut sessions = self
118→            .sessions
119→            .lock()
120→            .map_err(|_| "Lock error".to_string())?;
121→        let session = sessions
122→            .get_mut(session_id)
123→            .ok_or_else(|| "Session not found".to_string())?;
124→        session
125→            .writer
126→            .write_all(data)
127→            .map_err(|e| format!("Write error: {}", e))
128→    }
129→
130→    pub fn resize(&self, session_id: &str, cols: u16, rows: u16) -> Result<(), String> {
131→        let sessions = self
132→            .sessions
133→            .lock()
134→            .map_err(|_| "Lock error".to_string())?;
135→        let session = sessions
136→            .get(session_id)
137→            .ok_or_else(|| "Session not found".to_string())?;
138→        session
139→            .master
140→            .resize(PtySize {
141→                rows,
142→                cols,
143→                pixel_width: 0,
144→                pixel_height: 0,
145→            })
146→            .map_err(|e| format!("Resize error: {}", e))
147→    }
148→
149→    pub fn kill(&self, session_id: &str) -> Result<(), String> {
150→        let mut sessions = self
151→            .sessions
152→            .lock()
153→            .map_err(|_| "Lock error".to_string())?;
154→        sessions.remove(session_id);
155→        Ok(())
156→    }
157→}
