159→pub fn launch_ghostty_agent(repo_path: &str, agent: &str, prompt: &str) -> Result<(), String> {
160→    use std::io::Write as IoWrite;
161→
162→    let agent_cmd = match agent {
163→        "claude-code" => "claude",
164→        "codex" => "codex",
165→        _ => return Err(format!("Unknown agent: {}", agent)),
166→    };
167→
168→    // Write prompt to temp file
169→    let tmp_dir = std::env::temp_dir();
170→    let prompt_file = tmp_dir.join(format!("entire-prompt-{}.txt", uuid_v4()));
171→    let mut f = std::fs::File::create(&prompt_file)
172→        .map_err(|e| format!("Failed to create temp file: {}", e))?;
173→    f.write_all(prompt.as_bytes())
174→        .map_err(|e| format!("Failed to write prompt: {}", e))?;
175→    drop(f);
176→
177→    let prompt_path = prompt_file.to_string_lossy().to_string();
178→
179→    std::process::Command::new("ghostty")
180→        .arg("-e")
181→        .arg("sh")
182→        .arg("-c")
183→        .arg(format!(
184→            "cd '{}' && {} -p '{}'",
185→            repo_path.replace('\'', "'\\''"),
186→            agent_cmd,
187→            prompt_path.replace('\'', "'\\''")
188→        ))
189→        .spawn()
190→        .map_err(|e| format!("Failed to launch ghostty: {}", e))?;
191→
192→    Ok(())
193→}
