195→fn uuid_v4() -> String {
196→    use std::time::{SystemTime, UNIX_EPOCH};
197→    let now = SystemTime::now()
198→        .duration_since(UNIX_EPOCH)
199→        .unwrap_or_default();
200→    format!("pty-{}-{}", now.as_secs(), now.subsec_nanos())
201→}
