 25→/// Find the git common dir (handles worktrees)
 26→pub fn git_common_dir(repo_path: &str) -> PathBuf {
 27→    let git_dir = Path::new(repo_path).join(".git");
 28→    if git_dir.is_file() {
 29→        // Worktree: .git is a file containing "gitdir: /path/to/worktree/git"
 30→        if let Ok(content) = fs::read_to_string(&git_dir) {
 31→            if let Some(gitdir) = content.strip_prefix("gitdir: ") {
 32→                let gitdir = gitdir.trim();
 33→                let gitdir_path = if Path::new(gitdir).is_absolute() {
 34→                    PathBuf::from(gitdir)
 35→                } else {
 36→                    Path::new(repo_path).join(gitdir)
 37→                };
 38→                // commondir file tells us where the shared git dir is
 39→                let commondir_file = gitdir_path.join("commondir");
 40→                if let Ok(commondir) = fs::read_to_string(&commondir_file) {
 41→                    let commondir = commondir.trim();
 42→                    if Path::new(commondir).is_absolute() {
 43→                        return PathBuf::from(commondir);
 44→                    } else {
 45→                        return gitdir_path.join(commondir);
 46→                    }
 47→                }
 48→                return gitdir_path;
 49→            }
 50→        }
 51→    }
 52→    git_dir
 53→}
 54→
 55→/// List active sessions from .git/entire-sessions/
 56→pub fn list_active_sessions(repo_path: &str) -> Result<Vec<SessionState>, String> {
 57→    let sessions_dir = git_common_dir(repo_path).join("entire-sessions");
 58→    if !sessions_dir.exists() {
 59→        return Ok(Vec::new());
 60→    }
 61→
 62→    let mut sessions = Vec::new();
 63→    let entries =
 64→        fs::read_dir(&sessions_dir).map_err(|e| format!("Failed to read sessions dir: {}", e))?;
 65→
 66→    for entry in entries {
 67→        let entry = entry.map_err(|e| format!("Dir entry error: {}", e))?;
 68→        let path = entry.path();
 69→        if path.extension().map_or(false, |ext| ext == "json") {
 70→            if let Ok(content) = fs::read_to_string(&path) {
 71→                if let Ok(state) = serde_json::from_str::<SessionState>(&content) {
 72→                    sessions.push(state);
 73→                }
 74→            }
 75→        }
 76→    }
 77→
 78→    Ok(sessions)
 79→}
