 81→/// Read transcript from checkpoint data (Claude Code JSONL format)
 82→///
 83→/// Each line is a JSON envelope with a `type` field:
 84→///   - "user"      → message in `.message.content` (string or content blocks)
 85→///   - "assistant"  → message in `.message.content` (array of text/tool_use blocks)
 86→///   - "tool_result"→ tool output in `.content`
 87→///   - "progress", "system", "file-history-snapshot", "last-prompt" → skip
 88→pub fn read_transcript(content: &str) -> Vec<TranscriptMessage> {
 89→    let mut messages = Vec::new();
 90→
 91→    for line in content.lines() {
 92→        if line.trim().is_empty() {
 93→            continue;
 94→        }
 95→        let value: serde_json::Value = match serde_json::from_str(line) {
 96→            Ok(v) => v,
 97→            Err(_) => continue,
 98→        };
 99→
100→        let line_type = value.get("type").and_then(|t| t.as_str()).unwrap_or("");
101→        let timestamp = value.get("timestamp").and_then(|t| t.as_str()).map(|s| s.to_string());
102→
103→        match line_type {
104→            "user" => {
105→                let msg = match value.get("message") {
106→                    Some(m) => m,
107→                    None => continue,
108→                };
109→                let text = extract_message_content(msg);
110→                if !text.is_empty() {
111→                    messages.push(TranscriptMessage {
112→                        role: "user".to_string(),
113→                        content: text,
114→                        tool_name: None,
115→                        tool_input: None,
116→                        timestamp,
117→                    });
118→                }
119→            }
120→            "assistant" => {
121→                let msg = match value.get("message") {
122→                    Some(m) => m,
123→                    None => continue,
124→                };
125→                // Assistant content is an array of content blocks
126→                if let Some(blocks) = msg.get("content").and_then(|c| c.as_array()) {
127→                    for block in blocks {
128→                        let block_type = block.get("type").and_then(|t| t.as_str()).unwrap_or("");
129→                        match block_type {
130→                            "text" => {
131→                                let text = block.get("text").and_then(|t| t.as_str()).unwrap_or("");
132→                                if !text.is_empty() {
133→                                    messages.push(TranscriptMessage {
134→                                        role: "assistant".to_string(),
135→                                        content: text.to_string(),
136→                                        tool_name: None,
137→                                        tool_input: None,
138→                                        timestamp: timestamp.clone(),
139→                                    });
140→                                }
141→                            }
142→                            "tool_use" => {
143→                                let name = block.get("name").and_then(|n| n.as_str()).unwrap_or("unknown");
144→                                let input = block.get("input").map(|v| {
145→                                    serde_json::to_string_pretty(v).unwrap_or_default()
146→                                });
147→                                messages.push(TranscriptMessage {
148→                                    role: "assistant".to_string(),
149→                                    content: String::new(),
150→                                    tool_name: Some(name.to_string()),
151→                                    tool_input: input,
152→                                    timestamp: timestamp.clone(),
153→                                });
154→                            }
155→                            _ => {}
156→                        }
157→                    }
158→                }
159→            }
160→            "tool_result" => {
161→                // Tool results can have content at the top level
162→                let text = value
163→                    .get("content")
164→                    .and_then(|c| c.as_str())
165→                    .unwrap_or("")
166→                    .to_string();
167→                let tool_name = value
168→                    .get("tool_name")
169→                    .or_else(|| value.get("name"))
170→                    .and_then(|n| n.as_str())
171→                    .map(|s| s.to_string());
172→                if !text.is_empty() || tool_name.is_some() {
173→                    messages.push(TranscriptMessage {
174→                        role: "tool".to_string(),
175→                        content: text,
176→                        tool_name,
177→                        tool_input: None,
178→                        timestamp,
179→                    });
180→                }
181→            }
182→            _ => {
183→                // Skip progress, system, file-history-snapshot, last-prompt, etc.
184→            }
185→        }
186→    }
187→
188→    messages
189→}
190→
191→/// Extract text content from a message object (handles both string and content blocks)
192→fn extract_message_content(msg: &serde_json::Value) -> String {
193→    if let Some(content) = msg.get("content") {
194→        if let Some(text) = content.as_str() {
195→            return text.to_string();
196→        }
197→        if let Some(arr) = content.as_array() {
198→            let mut parts = Vec::new();
199→            for item in arr {
200→                if let Some(text) = item.get("text").and_then(|t| t.as_str()) {
201→                    parts.push(text.to_string());
202→                }
203→            }
204→            return parts.join("\n");
205→        }
206→    }
207→    String::new()
208→}
