 27→export default function App() {
 28→  const [tabs, setTabs] = useState<Tab[]>([
 29→    {
 30→      id: "main",
 31→      branch: "main",
 32→      repoPath: "",
 33→      worktree: null,
 34→      hasActiveSession: false,
 35→    },
 36→  ]);
 37→  const [activeTabId, setActiveTabId] = useState("main");
 38→  const [terminalHeight, setTerminalHeight] = useState(
 39→    () => Number(localStorage.getItem("entire:terminal-height")) || 220
 40→  );
 41→  const [isTerminalOpen, setIsTerminalOpen] = useState(
 42→    () => localStorage.getItem("entire:terminal-open") !== "false"
 43→  );
 44→  const [innerTab, setInnerTab] = useState<
 45→    "checkpoints" | "diff" | "insights" | "debug"
 46→  >("checkpoints");
 47→  const [selectedCheckpoint, setSelectedCheckpoint] =
 48→    useState<CheckpointSummary | null>(null);
 49→  const [checkpointInnerTab, setCheckpointInnerTab] = useState<
 50→    "transcript" | "diff" | "insights" | "debug"
 51→  >("transcript");
 52→
 53→  // Per-branch terminal sessions
 54→  const [sessionMap, setSessionMap] = useState<Map<string, TermSession>>(
 55→    () => new Map()
 56→  );
 57→
 58→  const terminalRef = useRef<TerminalPanelHandle>(null);
 59→
 60→  const activeTab = tabs.find((t) => t.id === activeTabId) ?? tabs[0];
 61→  const activeSession = sessionMap.get(activeTabId) ?? null;
 62→
 63→  // Live updates — watch active repo for checkpoint/session changes
 64→  useLiveUpdates(activeTab.repoPath);
 65→
 66→  const handleSessionChange = useCallback(
 67→    (session: TermSession | null) => {
 68→      setSessionMap((prev) => {
 69→        const next = new Map(prev);
 70→        if (session) {
 71→          next.set(activeTabId, session);
 72→        } else {
 73→          next.delete(activeTabId);
 74→        }
 75→        return next;
 76→      });
 77→    },
 78→    [activeTabId]
 79→  );
 80→
 81→  // Agent dispatch — launch external Ghostty window
 82→  const handleSendToAgent = useCallback(
 83→    (agent: string, prompt: string) => {
