113→
114→  // Keyboard shortcuts
115→  useEffect(() => {
116→    function onKeyDown(e: KeyboardEvent) {
117→      const meta = e.metaKey || e.ctrlKey;
118→
119→      // Cmd+K = focus search
120→      if (meta && e.key === "k") {
121→        e.preventDefault();
122→        document.querySelector<HTMLInputElement>('input[placeholder*="Search"]')?.focus();
123→      }
124→      // Ctrl+` = toggle terminal
125→      if (e.ctrlKey && e.key === "`") {
126→        e.preventDefault();
127→        setIsTerminalOpen((v) => !v);
128→      }
129→      // Cmd+W = close active tab
130→      if (meta && e.key === "w") {
131→        e.preventDefault();
132→        handleCloseTab(activeTabId);
133→      }
134→      // Cmd+1-9 = switch to tab by index
135→      if (meta && e.key >= "1" && e.key <= "9") {
136→        e.preventDefault();
137→        const idx = parseInt(e.key) - 1;
138→        if (idx < tabs.length) {
139→          setActiveTabId(tabs[idx].id);
140→        }
141→      }
142→      // Cmd+[ / Cmd+] = prev/next tab
143→      if (meta && e.key === "[") {
144→        e.preventDefault();
145→        const idx = tabs.findIndex((t) => t.id === activeTabId);
146→        if (idx > 0) setActiveTabId(tabs[idx - 1].id);
147→      }
148→      if (meta && e.key === "]") {
149→        e.preventDefault();
150→        const idx = tabs.findIndex((t) => t.id === activeTabId);
151→        if (idx < tabs.length - 1) setActiveTabId(tabs[idx + 1].id);
152→      }
153→      // Escape = deselect checkpoint
154→      if (e.key === "Escape" && selectedCheckpoint) {
155→        setSelectedCheckpoint(null);
156→      }
157→    }
158→    window.addEventListener("keydown", onKeyDown);
159→    return () => window.removeEventListener("keydown", onKeyDown);
160→  }, [activeTabId, tabs, selectedCheckpoint]);
161→
162→  function handleBranchSelect(branch: BranchInfo, repoPath: string) {
