271→                  }`}
272→                >
273→                  {tab === "checkpoints"
274→                    ? "Checkpoints"
275→                    : tab === "diff"
276→                      ? "Diff"
277→                      : tab === "insights"
278→                        ? "Insights"
279→                        : "Debug"}
280→                </button>
281→              ))}
282→            </div>
283→
284→            {/* Main view */}
285→            <div className="flex flex-1 overflow-hidden bg-bg">
286→              {innerTab === "checkpoints" && (
