417→fn watch_repo(
418→    repo_path: String,
419→    app: tauri::AppHandle,
420→    state: State<'_, Mutex<AppState>>,
421→) -> Result<(), String> {
422→    let mut app_state = state.lock().map_err(|_| "State lock error".to_string())?;
423→
424→    // Don't double-watch
425→    if app_state.watched_repos.contains(&repo_path) {
