  1→import { useState, useCallback, useImperativeHandle, forwardRef } from "react";
  2→import { invoke } from "@tauri-apps/api/core";
  3→import { XTerminal } from "./XTerminal";
  4→import type { Tab } from "../../App";
  5→
  6→export interface TerminalPanelHandle {
  7→  launchAgentWithPrompt: (agent: string, prompt: string) => Promise<void>;
  8→}
  9→
 10→interface TerminalPanelProps {
 11→  height: number;
 12→  tab: Tab;
 13→  onToggle: () => void;
 14→}
 15→
 16→interface TermSession {
 17→  id: string;
 18→  agent: string;
 19→  label: string;
 20→}
 21→
 22→export const TerminalPanel = forwardRef<TerminalPanelHandle, TerminalPanelProps>(
 23→  function TerminalPanel({ height, tab, onToggle }, ref) {
 24→  const [sessions, setSessions] = useState<TermSession[]>([]);
 25→  const [activeSessionIdx, setActiveSessionIdx] = useState(0);
 26→
 27→  const activeSession = sessions[activeSessionIdx] ?? null;
 28→
 29→  const launchAgent = useCallback(
 30→    async (agent: string) => {
 31→      if (!tab.repoPath) {
 32→        console.warn("No repo path set — cannot launch agent");
 33→        return "";
 34→      }
 35→      try {
 36→        const sessionId: string = await invoke("spawn_agent", {
 37→          repoPath: tab.repoPath,
 38→          agent,
 39→        });
 40→        const newSession: TermSession = {
 41→          id: sessionId,
 42→          agent,
 43→          label: `${agent === "claude-code" ? "Claude Code" : "Codex"} — ${tab.branch}`,
 44→        };
 45→        setSessions((prev) => [...prev, newSession]);
 46→        setActiveSessionIdx(sessions.length);
 47→        return sessionId;
 48→      } catch (err) {
 49→        console.error("Failed to spawn agent:", err);
 50→        return "";
 51→      }
 52→    },
 53→    [tab.repoPath, tab.branch, sessions.length]
 54→  );
 55→
 56→  useImperativeHandle(ref, () => ({
 57→    async launchAgentWithPrompt(agent: string, prompt: string) {
 58→      const sessionId = await launchAgent(agent);
 59→      if (!sessionId) return;
 60→      // Small delay for PTY initialization before sending input
 61→      setTimeout(async () => {
 62→        try {
 63→          await invoke("pty_input", { sessionId, data: prompt + "\n" });
 64→        } catch (err) {
 65→          console.error("Failed to send prompt to agent:", err);
 66→        }
 67→      }, 150);
 68→    },
 69→  }), [launchAgent]);
 70→
 71→  return (
