import { useEffect, useRef, useCallback } from "react";
import { Terminal } from "@xterm/xterm";
import { FitAddon } from "@xterm/addon-fit";
import { invoke } from "@tauri-apps/api/core";
import { useTauriEvent } from "../../hooks/use-tauri-event";
import "@xterm/xterm/css/xterm.css";

interface XTerminalProps {
  sessionId: string | null;
  className?: string;
}

export function XTerminal({ sessionId, className }: XTerminalProps) {
  const containerRef = useRef<HTMLDivElement>(null);
  const termRef = useRef<Terminal | null>(null);
  const fitAddonRef = useRef<FitAddon | null>(null);

  // Handle PTY output from Rust backend
  useTauriEvent<{ sessionId: string; data: number[] }>(
    "pty-output",
    useCallback(
      (payload) => {
        if (payload.sessionId === sessionId && termRef.current) {
          const bytes = new Uint8Array(payload.data);
          termRef.current.write(bytes);
        }
      },
      [sessionId]
    )
  );

  useEffect(() => {
    if (!containerRef.current) return;

    const term = new Terminal({
      fontFamily: "'SF Mono', 'Fira Code', 'Cascadia Code', monospace",
      fontSize: 13,
      lineHeight: 1.5,
      cursorBlink: true,
      cursorStyle: "block",
      theme: {
        background: "#0a0a0a",
        foreground: "#e4e4e7",
        cursor: "#7c3aed",
        cursorAccent: "#0a0a0a",
        selectionBackground: "#7c3aed44",
        black: "#0d0d0d",
        red: "#f87171",
        green: "#4ade80",
        yellow: "#fbbf24",
        blue: "#60a5fa",
        magenta: "#a78bfa",
        cyan: "#22d3ee",
        white: "#e4e4e7",
        brightBlack: "#555555",
        brightRed: "#fca5a5",
        brightGreen: "#86efac",
        brightYellow: "#fde68a",
        brightBlue: "#93c5fd",
        brightMagenta: "#c4b5fd",
        brightCyan: "#67e8f9",
        brightWhite: "#ffffff",
      },
    });

    const fitAddon = new FitAddon();
    term.loadAddon(fitAddon);
    term.open(containerRef.current);

    // Fit after a small delay to ensure container has dimensions
    requestAnimationFrame(() => {
      fitAddon.fit();
    });

    // Send user input to PTY
    term.onData((data) => {
      if (sessionId) {
        invoke("pty_input", { sessionId, data }).catch(console.error);
      }
    });

    // Resize PTY when terminal resizes
    term.onResize(({ cols, rows }) => {
      if (sessionId) {
        invoke("pty_resize", { sessionId, cols, rows }).catch(console.error);
      }
    });

    termRef.current = term;
    fitAddonRef.current = fitAddon;

    // Handle window resize
    const resizeObserver = new ResizeObserver(() => {
      requestAnimationFrame(() => {
        fitAddon.fit();
      });
    });
    resizeObserver.observe(containerRef.current);

    // Welcome message if no session
    if (!sessionId) {
      term.writeln("\x1b[38;2;124;58;237m");
      term.writeln("  ╔═══════════════════════════════════╗");
      term.writeln("  ║         Entire Desktop            ║");
      term.writeln("  ║                                   ║");
      term.writeln("  ║  Click 'New Session' to start     ║");
      term.writeln("  ║  a Claude Code or Codex session   ║");
      term.writeln("  ╚═══════════════════════════════════╝");
      term.writeln("\x1b[0m");
    }

    return () => {
      resizeObserver.disconnect();
      term.dispose();
      termRef.current = null;
      fitAddonRef.current = null;
    };
  }, [sessionId]);

  return (
    <div
      ref={containerRef}
      className={`h-full w-full ${className ?? ""}`}
      style={{ padding: "4px 8px" }}
    />
  );
}

