  1→import { useState, useEffect, useRef, useCallback } from "react";
  2→import { invoke } from "@tauri-apps/api/core";
  3→import { Sidebar } from "./features/repos/Sidebar";
  4→import { TitleBar } from "./components/TitleBar";
  5→import { TabBar } from "./components/TabBar";
  6→import { CheckpointList } from "./features/checkpoints/CheckpointList";
  7→import { TranscriptView } from "./features/transcripts/TranscriptView";
  8→import { DiffView, BranchDiffView } from "./features/diff/DiffView";
  9→import { CheckpointInsightsContainer } from "./features/insights/CheckpointInsightsContainer";
 10→import { BranchInsightsContainer } from "./features/insights/BranchInsightsContainer";
 11→import { BranchDebugContainer } from "./features/debug/BranchDebugContainer";
 12→import { CheckpointDebugContainer } from "./features/debug/CheckpointDebugContainer";
 13→import { TerminalPanel } from "./features/terminal/TerminalPanel";
 14→import type { TerminalPanelHandle, TermSession } from "./features/terminal/TerminalPanel";
 15→import { useLiveUpdates } from "./hooks/use-live-updates";
 16→import type { BranchInfo, CheckpointSummary, WorktreeInfo } from "./lib/ipc";
 17→import { ArrowLeft, GitCommit } from "lucide-react";
 18→
 19→export interface Tab {
 20→  id: string;
 21→  branch: string;
 22→  repoPath: string;
 23→  worktree: WorktreeInfo | null;
 24→  hasActiveSession: boolean;
 25→}
 26→
 27→export default function App() {
 28→  const [tabs, setTabs] = useState<Tab[]>([
 29→    {
 30→      id: "main",
 31→      branch: "main",
 32→      repoPath: "",
 33→      worktree: null,
 34→      hasActiveSession: false,
 35→    },
 36→  ]);
 37→  const [activeTabId, setActiveTabId] = useState("main");
 38→  const [terminalHeight, setTerminalHeight] = useState(
 39→    () => Number(localStorage.getItem("entire:terminal-height")) || 220
 40→  );
 41→  const [isTerminalOpen, setIsTerminalOpen] = useState(
 42→    () => localStorage.getItem("entire:terminal-open") !== "false"
 43→  );
 44→  const [innerTab, setInnerTab] = useState<
 45→    "checkpoints" | "diff" | "insights" | "debug"
 46→  >("checkpoints");
 47→  const [selectedCheckpoint, setSelectedCheckpoint] =
 48→    useState<CheckpointSummary | null>(null);
 49→  const [checkpointInnerTab, setCheckpointInnerTab] = useState<
 50→    "transcript" | "diff" | "insights" | "debug"
 51→  >("transcript");
 52→
 53→  // Per-branch terminal sessions
 54→  const [sessionMap, setSessionMap] = useState<Map<string, TermSession>>(
 55→    () => new Map()
 56→  );
 57→
 58→  const terminalRef = useRef<TerminalPanelHandle>(null);
 59→
 60→  const activeTab = tabs.find((t) => t.id === activeTabId) ?? tabs[0];
 61→  const activeSession = sessionMap.get(activeTabId) ?? null;
 62→
 63→  // Live updates — watch active repo for checkpoint/session changes
 64→  useLiveUpdates(activeTab.repoPath);
 65→
 66→  const handleSessionChange = useCallback(
 67→    (session: TermSession | null) => {
 68→      setSessionMap((prev) => {
 69→        const next = new Map(prev);
 70→        if (session) {
 71→          next.set(activeTabId, session);
 72→        } else {
 73→          next.delete(activeTabId);
 74→        }
 75→        return next;
 76→      });
 77→    },
 78→    [activeTabId]
 79→  );
 80→
 81→  // Agent dispatch — launch external Ghostty window
 82→  const handleSendToAgent = useCallback(
 83→    (agent: string, prompt: string) => {
 84→      invoke("launch_ghostty_agent", {
 85→        repoPath: activeTab.repoPath,
 86→        agent,
 87→        prompt,
 88→      }).catch((err: unknown) => {
 89→        console.error("Failed to launch external agent:", err);
 90→        // Fallback: open in embedded terminal
 91→        if (!isTerminalOpen) setIsTerminalOpen(true);
 92→        setTimeout(() => {
 93→          terminalRef.current?.launchAgentWithPrompt(agent, prompt);
 94→        }, isTerminalOpen ? 0 : 100);
 95→      });
 96→    },
 97→    [activeTab.repoPath, isTerminalOpen]
 98→  );
 99→
100→  // Persist UI state to localStorage
101→  useEffect(() => {
102→    localStorage.setItem("entire:terminal-height", String(terminalHeight));
103→  }, [terminalHeight]);
104→  useEffect(() => {
105→    localStorage.setItem("entire:terminal-open", String(isTerminalOpen));
106→  }, [isTerminalOpen]);
107→
108→  // Clear selected checkpoint when switching branch tabs
109→  useEffect(() => {
110→    setSelectedCheckpoint(null);
111→    setCheckpointInnerTab("transcript");
112→  }, [activeTabId]);
113→
114→  // Keyboard shortcuts
115→  useEffect(() => {
116→    function onKeyDown(e: KeyboardEvent) {
117→      const meta = e.metaKey || e.ctrlKey;
118→
119→      // Cmd+K = focus search
120→      if (meta && e.key === "k") {
121→        e.preventDefault();
122→        document.querySelector<HTMLInputElement>('input[placeholder*="Search"]')?.focus();
123→      }
124→      // Ctrl+` = toggle terminal
125→      if (e.ctrlKey && e.key === "`") {
126→        e.preventDefault();
127→        setIsTerminalOpen((v) => !v);
128→      }
129→      // Cmd+W = close active tab
130→      if (meta && e.key === "w") {
131→        e.preventDefault();
132→        handleCloseTab(activeTabId);
133→      }
134→      // Cmd+1-9 = switch to tab by index
135→      if (meta && e.key >= "1" && e.key <= "9") {
136→        e.preventDefault();
137→        const idx = parseInt(e.key) - 1;
138→        if (idx < tabs.length) {
139→          setActiveTabId(tabs[idx].id);
140→        }
141→      }
142→      // Cmd+[ / Cmd+] = prev/next tab
143→      if (meta && e.key === "[") {
144→        e.preventDefault();
145→        const idx = tabs.findIndex((t) => t.id === activeTabId);
146→        if (idx > 0) setActiveTabId(tabs[idx - 1].id);
147→      }
148→      if (meta && e.key === "]") {
149→        e.preventDefault();
150→        const idx = tabs.findIndex((t) => t.id === activeTabId);
151→        if (idx < tabs.length - 1) setActiveTabId(tabs[idx + 1].id);
152→      }
153→      // Escape = deselect checkpoint
154→      if (e.key === "Escape" && selectedCheckpoint) {
155→        setSelectedCheckpoint(null);
156→      }
157→    }
158→    window.addEventListener("keydown", onKeyDown);
159→    return () => window.removeEventListener("keydown", onKeyDown);
160→  }, [activeTabId, tabs, selectedCheckpoint]);
161→
162→  function handleBranchSelect(branch: BranchInfo, repoPath: string) {
163→    const existing = tabs.find(
164→      (t) => t.branch === branch.name && t.repoPath === repoPath
165→    );
166→    if (existing) {
167→      setActiveTabId(existing.id);
168→    } else {
169→      const newTab: Tab = {
170→        id: `${repoPath}:${branch.name}`,
171→        branch: branch.name,
172→        repoPath,
173→        worktree: null,
174→        hasActiveSession: false,
175→      };
176→      setTabs([...tabs, newTab]);
177→      setActiveTabId(newTab.id);
178→    }
179→  }
180→
181→  function handleWorktreeSelect(wt: WorktreeInfo, repoPath: string) {
182→    const existing = tabs.find(
183→      (t) => t.branch === wt.branch && t.repoPath === repoPath
184→    );
185→    if (existing) {
186→      setActiveTabId(existing.id);
187→    } else {
188→      const newTab: Tab = {
189→        id: `${repoPath}:${wt.branch}`,
190→        branch: wt.branch,
191→        repoPath,
192→        worktree: wt,
193→        hasActiveSession: false,
194→      };
195→      setTabs([...tabs, newTab]);
196→      setActiveTabId(newTab.id);
197→    }
198→  }
199→
200→  function handleCloseTab(tabId: string) {
201→    if (tabs.length <= 1) return;
202→    const idx = tabs.findIndex((t) => t.id === tabId);
203→    const newTabs = tabs.filter((t) => t.id !== tabId);
204→    setTabs(newTabs);
205→    if (activeTabId === tabId) {
206→      setActiveTabId(newTabs[Math.max(0, idx - 1)].id);
207→    }
208→    // Clean up session for closed tab
209→    setSessionMap((prev) => {
210→      const next = new Map(prev);
211→      next.delete(tabId);
212→      return next;
213→    });
214→  }
215→
216→  function handleResizeStart(e: React.MouseEvent) {
217→    e.preventDefault();
218→    const startY = e.clientY;
219→    const startHeight = terminalHeight;
220→
