import { useState, useEffect, useRef, useCallback } from "react";
import { invoke } from "@tauri-apps/api/core";
import { Sidebar } from "./features/repos/Sidebar";
import { TitleBar } from "./components/TitleBar";
import { TabBar } from "./components/TabBar";
import { CheckpointList } from "./features/checkpoints/CheckpointList";
import { TranscriptView } from "./features/transcripts/TranscriptView";
import { DiffView, BranchDiffView } from "./features/diff/DiffView";
import { CheckpointInsightsContainer } from "./features/insights/CheckpointInsightsContainer";
import { BranchInsightsContainer } from "./features/insights/BranchInsightsContainer";
import { BranchDebugContainer } from "./features/debug/BranchDebugContainer";
import { CheckpointDebugContainer } from "./features/debug/CheckpointDebugContainer";
import { TerminalPanel } from "./features/terminal/TerminalPanel";
import type { TerminalPanelHandle, TermSession } from "./features/terminal/TerminalPanel";
import { useLiveUpdates } from "./hooks/use-live-updates";
import type { BranchInfo, CheckpointSummary, WorktreeInfo } from "./lib/ipc";
import { ArrowLeft, GitCommit } from "lucide-react";

export interface Tab {
  id: string;
  branch: string;
  repoPath: string;
  worktree: WorktreeInfo | null;
  hasActiveSession: boolean;
}

export default function App() {
  const [tabs, setTabs] = useState<Tab[]>([
    {
      id: "main",
      branch: "main",
      repoPath: "",
      worktree: null,
      hasActiveSession: false,
    },
  ]);
  const [activeTabId, setActiveTabId] = useState("main");
  const [terminalHeight, setTerminalHeight] = useState(
    () => Number(localStorage.getItem("entire:terminal-height")) || 220
  );
  const [isTerminalOpen, setIsTerminalOpen] = useState(
    () => localStorage.getItem("entire:terminal-open") !== "false"
  );
  const [innerTab, setInnerTab] = useState<
    "checkpoints" | "diff" | "insights" | "debug"
  >("checkpoints");
  const [selectedCheckpoint, setSelectedCheckpoint] =
    useState<CheckpointSummary | null>(null);
  const [checkpointInnerTab, setCheckpointInnerTab] = useState<
    "transcript" | "diff" | "insights" | "debug"
  >("transcript");

  // Per-branch terminal sessions
  const [sessionMap, setSessionMap] = useState<Map<string, TermSession>>(
    () => new Map()
  );

  const terminalRef = useRef<TerminalPanelHandle>(null);

  const activeTab = tabs.find((t) => t.id === activeTabId) ?? tabs[0];
  const activeSession = sessionMap.get(activeTabId) ?? null;

  // Live updates — watch active repo for checkpoint/session changes
  useLiveUpdates(activeTab.repoPath);

  const handleSessionChange = useCallback(
    (session: TermSession | null) => {
      setSessionMap((prev) => {
        const next = new Map(prev);
        if (session) {
          next.set(activeTabId, session);
        } else {
          next.delete(activeTabId);
        }
        return next;
      });
    },
    [activeTabId]
  );

  // Agent dispatch — launch external Ghostty window
  const handleSendToAgent = useCallback(
    (agent: string, prompt: string) => {
      invoke("launch_ghostty_agent", {
        repoPath: activeTab.repoPath,
        agent,
        prompt,
      }).catch((err: unknown) => {
        console.error("Failed to launch external agent:", err);
        // Fallback: open in embedded terminal
        if (!isTerminalOpen) setIsTerminalOpen(true);
        setTimeout(() => {
          terminalRef.current?.launchAgentWithPrompt(agent, prompt);
        }, isTerminalOpen ? 0 : 100);
      });
    },
    [activeTab.repoPath, isTerminalOpen]
  );

  // Persist UI state to localStorage
  useEffect(() => {
    localStorage.setItem("entire:terminal-height", String(terminalHeight));
  }, [terminalHeight]);
  useEffect(() => {
    localStorage.setItem("entire:terminal-open", String(isTerminalOpen));
  }, [isTerminalOpen]);

  // Clear selected checkpoint when switching branch tabs
  useEffect(() => {
    setSelectedCheckpoint(null);
    setCheckpointInnerTab("transcript");
  }, [activeTabId]);

  // Keyboard shortcuts
  useEffect(() => {
    function onKeyDown(e: KeyboardEvent) {
      const meta = e.metaKey || e.ctrlKey;

      // Cmd+K = focus search
      if (meta && e.key === "k") {
        e.preventDefault();
        document.querySelector<HTMLInputElement>('input[placeholder*="Search"]')?.focus();
      }
      // Ctrl+` = toggle terminal
      if (e.ctrlKey && e.key === "`") {
        e.preventDefault();
        setIsTerminalOpen((v) => !v);
      }
      // Cmd+W = close active tab
      if (meta && e.key === "w") {
        e.preventDefault();
        handleCloseTab(activeTabId);
      }
      // Cmd+1-9 = switch to tab by index
      if (meta && e.key >= "1" && e.key <= "9") {
        e.preventDefault();
        const idx = parseInt(e.key) - 1;
        if (idx < tabs.length) {
          setActiveTabId(tabs[idx].id);
        }
      }
      // Cmd+[ / Cmd+] = prev/next tab
      if (meta && e.key === "[") {
        e.preventDefault();
        const idx = tabs.findIndex((t) => t.id === activeTabId);
        if (idx > 0) setActiveTabId(tabs[idx - 1].id);
      }
      if (meta && e.key === "]") {
        e.preventDefault();
        const idx = tabs.findIndex((t) => t.id === activeTabId);
        if (idx < tabs.length - 1) setActiveTabId(tabs[idx + 1].id);
      }
      // Escape = deselect checkpoint
      if (e.key === "Escape" && selectedCheckpoint) {
        setSelectedCheckpoint(null);
      }
    }
    window.addEventListener("keydown", onKeyDown);
    return () => window.removeEventListener("keydown", onKeyDown);
  }, [activeTabId, tabs, selectedCheckpoint]);

  function handleBranchSelect(branch: BranchInfo, repoPath: string) {
    const existing = tabs.find(
      (t) => t.branch === branch.name && t.repoPath === repoPath
    );
    if (existing) {
      setActiveTabId(existing.id);
    } else {
      const newTab: Tab = {
        id: `${repoPath}:${branch.name}`,
        branch: branch.name,
        repoPath,
        worktree: null,
        hasActiveSession: false,
      };
      setTabs([...tabs, newTab]);
      setActiveTabId(newTab.id);
    }
  }

  function handleWorktreeSelect(wt: WorktreeInfo, repoPath: string) {
    const existing = tabs.find(
      (t) => t.branch === wt.branch && t.repoPath === repoPath
    );
    if (existing) {
      setActiveTabId(existing.id);
    } else {
      const newTab: Tab = {
        id: `${repoPath}:${wt.branch}`,
        branch: wt.branch,
        repoPath,
        worktree: wt,
        hasActiveSession: false,
      };
      setTabs([...tabs, newTab]);
      setActiveTabId(newTab.id);
    }
  }

  function handleCloseTab(tabId: string) {
    if (tabs.length <= 1) return;
    const idx = tabs.findIndex((t) => t.id === tabId);
    const newTabs = tabs.filter((t) => t.id !== tabId);
    setTabs(newTabs);
    if (activeTabId === tabId) {
      setActiveTabId(newTabs[Math.max(0, idx - 1)].id);
    }
    // Clean up session for closed tab
    setSessionMap((prev) => {
      const next = new Map(prev);
      next.delete(tabId);
      return next;
    });
  }

  function handleResizeStart(e: React.MouseEvent) {
    e.preventDefault();
    const startY = e.clientY;
    const startHeight = terminalHeight;

    function onMouseMove(ev: MouseEvent) {
      const delta = startY - ev.clientY;
      setTerminalHeight(Math.max(100, Math.min(600, startHeight + delta)));
    }
    function onMouseUp() {
      window.removeEventListener("mousemove", onMouseMove);
      window.removeEventListener("mouseup", onMouseUp);
    }
    window.addEventListener("mousemove", onMouseMove);
    window.addEventListener("mouseup", onMouseUp);
  }

  const repoName = activeTab.repoPath
    ? activeTab.repoPath.split("/").pop()
    : "";

  return (
    <div className="flex h-screen flex-col">
      <TitleBar
        title={`Entire — ${repoName ? `${repoName}/` : ""}${activeTab?.branch ?? ""}`}
      />

      <div className="flex flex-1 overflow-hidden">
        {/* Sidebar */}
        <Sidebar
          activeTab={activeTab}
          onBranchSelect={handleBranchSelect}
          onWorktreeSelect={handleWorktreeSelect}
        />

        {/* Main content */}
        <div className="flex flex-1 flex-col overflow-hidden">
          <TabBar
            tabs={tabs}
            activeTabId={activeTabId}
            onSelectTab={setActiveTabId}
            onCloseTab={handleCloseTab}
          />

          <div className="flex flex-1 flex-col overflow-hidden">
            {/* Inner tabs */}
            <div className="flex gap-0 border-b border-border-subtle bg-bg px-5 pt-3">
              {(["checkpoints", "diff", "insights", "debug"] as const).map((tab) => (
                <button
                  key={tab}
                  onClick={() => setInnerTab(tab)}
                  className={`border-b-2 px-4 pb-2 text-xs font-medium capitalize transition-colors ${
                    innerTab === tab
                      ? "border-accent text-fg"
                      : "border-transparent text-fg-subtle hover:text-fg-muted"
                  }`}
                >
                  {tab === "checkpoints"
                    ? "Checkpoints"
                    : tab === "diff"
                      ? "Diff"
                      : tab === "insights"
                        ? "Insights"
                        : "Debug"}
                </button>
              ))}
            </div>

            {/* Main view */}
            <div className="flex flex-1 overflow-hidden bg-bg">
              {innerTab === "checkpoints" && (
                <>
                  {/* Checkpoint list — always visible when on checkpoints tab */}
                  <div
                    className={`overflow-y-auto ${
                      selectedCheckpoint
                        ? "w-[320px] shrink-0 border-r border-border-subtle"
                        : "flex-1"
                    }`}
                  >
                    <CheckpointList
                      repoPath={activeTab.repoPath}
                      branch={activeTab.branch}
                      onSelectCheckpoint={(cp) => {
                        setSelectedCheckpoint(cp);
                        setCheckpointInnerTab("transcript");
                      }}
                    />
                  </div>

                  {/* Checkpoint detail panel */}
                  {selectedCheckpoint && (
                    <div className="flex flex-1 flex-col overflow-hidden">
                      {/* Detail header */}
                      <div className="flex items-center gap-3 border-b border-border-subtle px-4 py-2.5">
                        <button
                          onClick={() => setSelectedCheckpoint(null)}
                          className="flex items-center gap-1.5 text-xs text-fg-subtle transition-colors hover:text-fg"
                        >
                          <ArrowLeft size={14} />
                        </button>
                        <GitCommit size={14} className="text-fg-subtle" />
                        <span className="font-mono text-xs text-accent-fg">
                          {selectedCheckpoint.commit_sha
                            ? selectedCheckpoint.commit_sha.slice(0, 7)
                            : selectedCheckpoint.checkpoint_id.slice(0, 7)}
                        </span>
                        <span className="truncate text-xs text-fg-muted">
                          {selectedCheckpoint.commit_message || "Untitled"}
                        </span>
                      </div>

                      {/* Checkpoint sub-tabs */}
                      <div className="flex gap-0 border-b border-border-subtle bg-bg px-4 pt-2">
                        {(["transcript", "diff", "insights", "debug"] as const).map(
                          (tab) => (
                            <button
                              key={tab}
                              onClick={() => setCheckpointInnerTab(tab)}
                              className={`border-b-2 px-3 pb-1.5 text-[11px] font-medium capitalize transition-colors ${
                                checkpointInnerTab === tab
                                  ? "border-accent text-fg"
                                  : "border-transparent text-fg-subtle hover:text-fg-muted"
                              }`}
                            >
                              {tab === "transcript"
                                ? "Transcript"
                                : tab === "diff"
                                  ? "Diff"
                                  : tab === "insights"
                                    ? "Insights"
                                    : "Debug"}
                            </button>
                          )
                        )}
                      </div>

                      {/* Checkpoint detail content */}
                      <div className="flex-1 overflow-y-auto">
                        {checkpointInnerTab === "transcript" && (
                          <TranscriptView
                            repoPath={activeTab.repoPath}
                            checkpoint={selectedCheckpoint}
                          />
                        )}
                        {checkpointInnerTab === "diff" && (
                          <DiffView
                            repoPath={activeTab.repoPath}
                            checkpoint={selectedCheckpoint}
                            onSendToAgent={handleSendToAgent}
                          />
                        )}
                        {checkpointInnerTab === "insights" && (
                          <CheckpointInsightsContainer
                            repoPath={activeTab.repoPath}
                            checkpoint={selectedCheckpoint}
                          />
                        )}
                        {checkpointInnerTab === "debug" && (
                          <CheckpointDebugContainer
                            repoPath={activeTab.repoPath}
                            checkpoint={selectedCheckpoint}
                          />
                        )}
                      </div>
                    </div>
                  )}
                </>
              )}
              {innerTab === "diff" && (
                <div className="flex flex-1 overflow-hidden">
                  <BranchDiffView
                    repoPath={activeTab.repoPath}
                    branch={activeTab.branch}
                    onSendToAgent={handleSendToAgent}
                  />
                </div>
              )}
              {innerTab === "insights" && (
                <div className="flex flex-1 overflow-y-auto">
                  <BranchInsightsContainer
                    repoPath={activeTab.repoPath}
                    branch={activeTab.branch}
                  />
                </div>
              )}
              {innerTab === "debug" && (
                <div className="flex flex-1 overflow-y-auto">
                  <BranchDebugContainer
                    repoPath={activeTab.repoPath}
                    branch={activeTab.branch}
                  />
                </div>
              )}
            </div>

            {/* Resize handle */}
            {isTerminalOpen && (
              <div
                onMouseDown={handleResizeStart}
                className="h-[3px] shrink-0 cursor-row-resize bg-border transition-colors hover:bg-accent"
              />
            )}

            {/* Terminal panel */}
            {isTerminalOpen && (
              <TerminalPanel
                ref={terminalRef}
                height={terminalHeight}
                tab={activeTab}
                session={activeSession}
                onSessionChange={handleSessionChange}
                onToggle={() => setIsTerminalOpen(false)}
              />
            )}
          </div>
        </div>
      </div>

      {!isTerminalOpen && (
        <button
          onClick={() => setIsTerminalOpen(true)}
          className="flex h-7 shrink-0 items-center justify-center border-t border-border bg-bg-raised text-[11px] text-fg-subtle hover:text-fg-muted"
        >
          ▲ Terminal (⌃`)
        </button>
      )}
    </div>
  );
}

