import { invoke } from "@tauri-apps/api/core";

// Git types
export interface RepoInfo {
  path: string;
  name: string;
  branches: BranchInfo[];
  worktrees: WorktreeInfo[];
}

export interface BranchInfo {
  name: string;
  is_head: boolean;
  checkpoint_count: number;
}

export interface WorktreeInfo {
  path: string;
  branch: string;
  is_main: boolean;
}

// Checkpoint types
export interface CheckpointSummary {
  checkpoint_id: string;
  branch: string;
  commit_sha: string;
  commit_message: string;
  files_touched: string[];
  sessions: SessionSummary[];
  token_usage: TokenUsage | null;
  created_at: string;
}

export interface SessionSummary {
  session_id: string;
  agent: string;
  model: string | null;
  step_count: number;
  summary: SessionSummaryInfo | null;
  token_usage: TokenUsage | null;
  initial_attribution: Attribution | null;
}

export interface SessionSummaryInfo {
  intent: string;
  outcome: string;
}

export interface TokenUsage {
  input_tokens: number;
  output_tokens: number;
  cache_creation_tokens: number;
  cache_read_tokens: number;
}

export interface Attribution {
  agent_lines: number;
  human_added: number;
  human_modified: number;
  total_committed: number;
  agent_percentage: number;
}

// Session/transcript types
export interface TranscriptMessage {
  role: "user" | "assistant" | "tool";
  content: string;
  tool_name: string | null;
  tool_input: string | null;
  timestamp: string | null;
}

// Diff types
export interface FileDiff {
  path: string;
  status: "added" | "modified" | "deleted";
  hunks: DiffHunk[];
}

export interface DiffHunk {
  header: string;
  lines: DiffLine[];
}

export interface DiffLine {
  kind: "add" | "delete" | "context";
  content: string;
  old_lineno: number | null;
  new_lineno: number | null;
}

// Session state (matches Rust SessionState)
export interface SessionState {
  SessionID: string | null;
  BaseCommit: string | null;
  Phase: string | null;
  AgentType: string | null;
  ModelName: string | null;
  StepCount: number | null;
  FilesTouched: string[] | null;
}

// Debug types
export interface EntireSettings {
  enabled: boolean | null;
  local_dev: boolean | null;
  log_level: string | null;
  telemetry: boolean | null;
}

export interface EntireLogResult {
  lines: string[];
  total_lines: number;
  file_size_bytes: number;
}

// PTY types
export interface PtySession {
  id: string;
  agent: string;
  repo_path: string;
  branch: string;
}

// IPC wrappers
export async function listRepos(): Promise<RepoInfo[]> {
  return invoke("list_repos");
}

export async function listCheckpoints(
  repoPath: string,
  branch: string
): Promise<CheckpointSummary[]> {
  return invoke("list_checkpoints", { repoPath, branch });
}

export async function getTranscript(
  repoPath: string,
  checkpointId: string,
  sessionIndex: number
): Promise<TranscriptMessage[]> {
  return invoke("get_transcript", { repoPath, checkpointId, sessionIndex });
}

export async function spawnAgent(
  repoPath: string,
  agent: string
): Promise<string> {
  return invoke("spawn_agent", { repoPath, agent });
}

export async function ptyInput(sessionId: string, data: string): Promise<void> {
  return invoke("pty_input", { sessionId, data });
}

export async function ptyResize(
  sessionId: string,
  cols: number,
  rows: number
): Promise<void> {
  return invoke("pty_resize", { sessionId, cols, rows });
}

export async function killPty(sessionId: string): Promise<void> {
  return invoke("kill_pty", { sessionId });
}

export async function getBranchDiff(
  repoPath: string,
  branch: string
): Promise<FileDiff[]> {
  return invoke("get_branch_diff", { repoPath, branch });
}

export async function getCheckpointDiff(
  repoPath: string,
  commitSha: string
): Promise<FileDiff[]> {
  return invoke("get_checkpoint_diff", { repoPath, commitSha });
}

export async function listSessions(
  repoPath: string
): Promise<SessionState[]> {
  return invoke("list_sessions", { repoPath });
}

export async function getEntireSettings(
  repoPath: string
): Promise<EntireSettings> {
  return invoke("get_entire_settings", { repoPath });
}

export async function getEntireLogs(
  repoPath: string,
  tailLines: number
): Promise<EntireLogResult> {
  return invoke("get_entire_logs", { repoPath, tailLines });
}

export async function getRawCheckpointMetadata(
  repoPath: string,
  checkpointId: string
): Promise<string> {
  return invoke("get_raw_checkpoint_metadata", { repoPath, checkpointId });
}

export async function getRawSessionFile(
  repoPath: string,
  sessionId: string
): Promise<string> {
  return invoke("get_raw_session_file", { repoPath, sessionId });
}

