/**
 * Ghostty Embedding API
 *
 * Minimal header for libghostty FFI from GhosttyKit.xcframework.
 * Build from source: https://github.com/manaflow-ai/ghostty
 *   zig build -Demit-xcframework=true -Dxcframework-target=universal -Doptimize=ReleaseFast
 *
 * Copy libghostty.a from GhosttyKit.xcframework/macos-arm64_x86_64/ into this directory.
 */

#ifndef GHOSTTY_H
#define GHOSTTY_H

#include <stdbool.h>
#include <stddef.h>
#include <stdint.h>

#ifdef __cplusplus
extern "C" {
#endif

/* ---------- Opaque handles ---------- */

typedef void* ghostty_app_t;
typedef void* ghostty_config_t;
typedef void* ghostty_surface_t;
typedef void* ghostty_inspector_t;

/* ---------- Enums ---------- */

typedef enum {
    GHOSTTY_PLATFORM_MACOS = 0,
    GHOSTTY_PLATFORM_IOS = 1,
} ghostty_platform_e;

typedef enum {
    GHOSTTY_CLIPBOARD_STANDARD = 0,
    GHOSTTY_CLIPBOARD_SELECTION = 1,
    GHOSTTY_CLIPBOARD_PRIMARY = 2,
} ghostty_clipboard_e;

typedef enum {
    GHOSTTY_CLIPBOARD_REQUEST_PASTE = 0,
    GHOSTTY_CLIPBOARD_REQUEST_OSC_52_READ = 1,
} ghostty_clipboard_request_e;

typedef enum {
    GHOSTTY_MOUSE_PRESS = 0,
    GHOSTTY_MOUSE_RELEASE = 1,
} ghostty_input_mouse_state_e;

typedef enum {
    GHOSTTY_MOUSE_BUTTON_LEFT = 0,
    GHOSTTY_MOUSE_BUTTON_RIGHT = 1,
    GHOSTTY_MOUSE_BUTTON_MIDDLE = 2,
} ghostty_input_mouse_button_e;

typedef enum {
    GHOSTTY_MODS_NONE = 0,
    GHOSTTY_MODS_SHIFT = 1 << 0,
    GHOSTTY_MODS_CTRL = 1 << 1,
    GHOSTTY_MODS_ALT = 1 << 2,
    GHOSTTY_MODS_SUPER = 1 << 3,
} ghostty_input_mods_e;

typedef enum {
    GHOSTTY_SURFACE_CONTEXT_WINDOW = 0,
    GHOSTTY_SURFACE_CONTEXT_EMBEDDED = 1,
} ghostty_surface_context_e;

/* ---------- Structs ---------- */

typedef struct {
    const char* key;
    const char* value;
} ghostty_env_var_s;

typedef struct {
    const char* data;
    size_t len;
} ghostty_clipboard_content_s;

typedef struct {
    bool precision;
} ghostty_input_scroll_mods_t;

/* Forward declarations for action types */
typedef struct ghostty_target_s ghostty_target_s;
typedef struct ghostty_action_s ghostty_action_s;

typedef struct {
    uint32_t keycode;
    const char* text;
    size_t text_len;
    ghostty_input_mods_e mods;
    bool composing;
} ghostty_input_key_s;

/* ---------- Runtime callbacks ---------- */

typedef void (*ghostty_runtime_wakeup_cb)(void* userdata);

typedef bool (*ghostty_runtime_action_cb)(
    ghostty_app_t app,
    ghostty_target_s target,
    ghostty_action_s action
);

typedef bool (*ghostty_runtime_read_clipboard_cb)(
    void* userdata,
    ghostty_clipboard_e clipboard,
    void* state
);

typedef void (*ghostty_runtime_confirm_read_clipboard_cb)(
    void* userdata,
    const char* content,
    void* state,
    ghostty_clipboard_request_e request
);

typedef void (*ghostty_runtime_write_clipboard_cb)(
    void* userdata,
    ghostty_clipboard_e clipboard,
    const ghostty_clipboard_content_s* content,
    size_t content_len,
    bool confirm
);

typedef void (*ghostty_runtime_close_surface_cb)(
    void* userdata,
    bool process_alive
);

/* ---------- Config structs ---------- */

typedef struct {
    void* userdata;
    bool supports_selection_clipboard;
    ghostty_runtime_wakeup_cb wakeup_cb;
    ghostty_runtime_action_cb action_cb;
    ghostty_runtime_read_clipboard_cb read_clipboard_cb;
    ghostty_runtime_confirm_read_clipboard_cb confirm_read_clipboard_cb;
    ghostty_runtime_write_clipboard_cb write_clipboard_cb;
    ghostty_runtime_close_surface_cb close_surface_cb;
} ghostty_runtime_config_s;

typedef union {
    void* nsview; /* macOS: NSView* */
    void* uiview; /* iOS: UIView* */
} ghostty_platform_u;

typedef struct {
    ghostty_platform_e platform_tag;
    ghostty_platform_u platform;
    void* userdata;
    double scale_factor;
    float font_size;
    const char* working_directory;
    const char* command;
    ghostty_env_var_s* env_vars;
    size_t env_var_count;
    const char* initial_input;
    bool wait_after_command;
    ghostty_surface_context_e context;
} ghostty_surface_config_s;

/* ---------- Lifecycle ---------- */

int ghostty_init(uintptr_t argc, char** argv);

ghostty_config_t ghostty_config_new(void);
void ghostty_config_load_default_files(ghostty_config_t config);
void ghostty_config_load_file(ghostty_config_t config, const char* path);
void ghostty_config_finalize(ghostty_config_t config);
void ghostty_config_free(ghostty_config_t config);
void ghostty_config_set(ghostty_config_t config, const char* key, const char* value);

ghostty_app_t ghostty_app_new(
    const ghostty_runtime_config_s* runtime_config,
    ghostty_config_t config
);
void ghostty_app_free(ghostty_app_t app);
bool ghostty_app_tick(ghostty_app_t app);

/* ---------- Surface ---------- */

ghostty_surface_t ghostty_surface_new(
    ghostty_app_t app,
    const ghostty_surface_config_s* config
);
void ghostty_surface_free(ghostty_surface_t surface);

void ghostty_surface_draw(ghostty_surface_t surface);
void ghostty_surface_set_size(ghostty_surface_t surface, uint32_t width, uint32_t height);
void ghostty_surface_set_focus(ghostty_surface_t surface, bool focused);

bool ghostty_surface_key(ghostty_surface_t surface, ghostty_input_key_s key);
void ghostty_surface_text(ghostty_surface_t surface, const char* text, size_t len);

bool ghostty_surface_mouse_button(
    ghostty_surface_t surface,
    ghostty_input_mouse_state_e state,
    ghostty_input_mouse_button_e button,
    ghostty_input_mods_e mods
);
void ghostty_surface_mouse_pos(
    ghostty_surface_t surface,
    double x,
    double y,
    ghostty_input_mods_e mods
);
void ghostty_surface_mouse_scroll(
    ghostty_surface_t surface,
    double dx,
    double dy,
    ghostty_input_scroll_mods_t mods
);

#ifdef __cplusplus
}
#endif

#endif /* GHOSTTY_H */

